import sys
import json

def solve(data: str) -> str:
    try:
        call = json.loads(data)
    except json.JSONDecodeError:
        return 'denied'
    valid = (isinstance(call, dict) and set(call) == {'tool','arguments'} and call.get('tool') == 'lookup' and isinstance(call.get('arguments'), dict) and set(call['arguments']) == {'id'} and isinstance(call['arguments']['id'], str) and bool(call['arguments']['id']))
    return 'authorized' if valid else 'denied'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
